#include<bits/stdc++.h>
using  namespace std;
long long n, x, sum, mindp, maxdp, minn = 1000000000, maxx = -1000000000, maxxx = -100000000;
int main() {
	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> x;
		sum += x;
		maxxx = max(maxxx, x);
		maxdp = max(x, maxdp + x);
		maxx = max(maxdp, maxx);
		mindp = min(x, mindp + x);
		minn = min(mindp, minn);
	}
	if(maxxx<0){
		cout<<maxxx;
	}else{
		cout << max(sum - minn, maxx);
    }
	return 0;
}
